SELECT 
    ROUND(
        COUNT(CASE WHEN SEX = 'F' AND Birthday > '1930-12-31' THEN 1 END) * 100.0 / COUNT(*), 
        2
    ) AS female_percentage_after_1930
FROM Patient;

SELECT 
    ROUND(
        (SELECT COUNT(*) FROM Patient WHERE SEX = 'F' AND Birthday > '1930-12-31') * 100.0 / 
        (SELECT COUNT(*) FROM Patient), 
        2
    ) AS female_percentage_after_1930;

